/**
 * @summary Check handle availability
 */
export const getCheckHandleUrl = (params: CheckHandleParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/v1/handles/check?${stringifiedParams}`
    : `/api/v1/handles/check`;
};

export const checkHandle = async (
  params: CheckHandleParams,
  options?: RequestInit,
): Promise<HandleCheckResult> => {
  return customFetch<HandleCheckResult>(getCheckHandleUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getCheckHandleQueryKey = (params?: CheckHandleParams) => {
  return [`/api/v1/handles/check`, ...(params ? [params] : [])] as const;
};

export const getCheckHandleQueryOptions = <
  TData = Awaited<ReturnType<typeof checkHandle>>,
  TError = ErrorType<unknown>,
>(
  params: CheckHandleParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof checkHandle>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getCheckHandleQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof checkHandle>>> = ({
    signal,
  }) => checkHandle(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof checkHandle>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

